const { execSync } = require('child_process');
try {
  const result = execSync(
    'ls -1 /data/invoices/*.pdf /data/invoices/*.PDF /data/invoices/*.jpg /data/invoices/*.JPG /data/invoices/*.jpeg /data/invoices/*.JPEG 2>/dev/null || echo ""',
    { encoding: 'utf8', shell: '/bin/sh' }
  );
  return [{ json: { stdout: result } }];
} catch(e) {
  return [{ json: { stdout: '' } }];
}

const stdout = $input.first().json.stdout || '';
const files = stdout.trim().split('\n').filter(f => {
  const trimmed = f.trim();
  return trimmed.length > 0 && trimmed !== "''" && trimmed !== "'";
});
if (files.length === 0) { return []; }
return files.map(filePath => ({
  json: {
    filePath: filePath.trim(),
    fileName: filePath.trim().split('/').pop()
  }
}));

const fs   = require('fs');
const path = require('path');
const filePath = $json.filePath;
const fileName = $json.fileName;
const fileBuffer = fs.readFileSync(filePath);
const base64Data = fileBuffer.toString('base64');
const ext = path.extname(fileName).toLowerCase();
const mimeTypes = { '.pdf': 'application/pdf', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.png': 'image/png' };
const mimeType = mimeTypes[ext] || 'application/octet-stream';
return {
  json: { filePath, fileName },
  binary: {
    data: { data: base64Data, mimeType: mimeType, fileName: fileName }
  }
};

// ── POLL UNSTRACT UNTIL COMPLETE ─────────────────────────────────────────
// POST response: { message: { execution_status, status_api, result } }
// GET poll response: { status: 'COMPLETED'|'PENDING', message: [result array] }
// Status values: PENDING, COMPLETED (from CeleryTaskState enum)

const { execSync } = require('child_process');
const uploadResp = $input.item.json;   // { message: { execution_status, status_api, result } }
const fileInfo   = $('Parse File List').item.json;

const UNSTRACT_KEY = 'fd0be776-0885-4a15-9d20-16e666b06f96';
const MAX_RETRIES  = 60;   // 60 x 10s = 10 min max
const POLL_SLEEP   = 10;   // seconds

function poll(statusApiPath) {
  const url = 'http://unstract-backend:8000' + statusApiPath;
  const raw = execSync(
    'wget -qO- --header="Authorization: Bearer ' + UNSTRACT_KEY + '" "' + url + '"',
    { encoding: 'utf8', shell: '/bin/sh', timeout: 30000 }
  );
  return JSON.parse(raw.trim());
  // Returns: { status: 'COMPLETED'|'PENDING', message: resultArray|null }
}

// ── Determine if we need to poll ─────────────────────────────────────────
const msgBlock   = uploadResp.message || {};
const initStatus = msgBlock.execution_status || '';
const statusApi  = msgBlock.status_api || null;

let finalResult = null;  // will hold the result array

if (initStatus === 'COMPLETED') {
  // Synchronous response - result is directly available
  finalResult = msgBlock.result;
} else if (initStatus === 'PENDING' && statusApi) {
  // Async - need to poll
  let retries = 0;
  while (retries < MAX_RETRIES) {
    execSync('sleep ' + POLL_SLEEP, { shell: '/bin/sh' });
    try {
      const polled  = poll(statusApi);
      const pollSt  = polled.status || '';
      if (pollSt === 'COMPLETED') {
        finalResult = polled.message;  // message IS the result array on GET
        break;
      }
      if (pollSt !== 'PENDING') break;  // ERROR or unknown - stop polling
    } catch(e) { /* transient - keep polling */ }
    retries++;
  }
} else {
  // Unexpected - try to use whatever came back
  finalResult = msgBlock.result || null;
}

// ── Extract invoice data from result ─────────────────────────────────────
// finalResult is an array like:
// [ { file: 'name.pdf', result: { output: { key: { invoice_data, amounts, vat_classification } } } } ]
let extractedData = {};
let parseOk = false;
try {
  if (Array.isArray(finalResult) && finalResult.length > 0) {
    const item   = finalResult[0];
    const output = item.result?.output || {};
    const key    = Object.keys(output)[0];
    if (key) { extractedData = output[key]; parseOk = true; }
  }
} catch(e) { extractedData = {}; parseOk = false; }

return {
  json: {
    invoice_data:       extractedData.invoice_data       || {},
    amounts:            extractedData.amounts            || {},
    vat_classification: extractedData.vat_classification || {},
    originalPath:       fileInfo.filePath,
    fileName:           fileInfo.fileName,
    parseOk:            parseOk
  }
};

const d   = $input.item.json;
const inv = d.invoice_data || {};
const amt = d.amounts      || {};
const errors = [];
if (!inv['Data'] || String(inv['Data']).trim() === '')                        errors.push('missing_date');
if (!inv["'Numri i fatur\u00ebs"] && !inv['Numri i fatur\u00ebs'])            errors.push('missing_invoice_number');
if (!inv['Emri i shit\u00ebsit'] || String(inv['Emri i shit\u00ebsit']).trim() === '') errors.push('missing_supplier');
const hasAmount = Object.values(amt).some(v => { const n = parseFloat(v); return !isNaN(n) && n > 0; });
if (!hasAmount) errors.push('no_positive_amounts');
return { json: { ...d, validation_passed: errors.length === 0, validation_errors: errors } };

const { execSync } = require('child_process');
const originalPath   = String($json.originalPath || '');
const fileName       = String($json.fileName     || 'unknown');
const validationErrs = Array.isArray($json.validation_errors)
  ? $json.validation_errors.map(String).join(',')
  : String($json.validation_errors || '');
try {
  execSync(
    'mkdir -p /data/invoices/Review && ts=$(date +%Y%m%d_%H%M%S) && mv "' + originalPath + '" "/data/invoices/Review/' + fileName + '-FAILED-$ts"',
    { encoding: 'utf8', shell: '/bin/sh' }
  );
  return { json: { status: 'routed_to_review', fileName: fileName, errors: validationErrs } };
} catch(e) {
  return { json: { status: 'move_error', fileName: fileName, error: String(e.message) } };
}

const data = $input.item.json;
const inv  = data.invoice_data || {};
const jsonForExcel  = { invoice_data: data.invoice_data, amounts: data.amounts, vat_classification: data.vat_classification };
const excelBase64   = Buffer.from(JSON.stringify(jsonForExcel),        'utf8').toString('base64');
const archiveBase64 = Buffer.from(JSON.stringify(data.invoice_data),  'utf8').toString('base64');
const supplier = (inv['Emri i shit\u00ebsit'] || 'UNKNOWN').replace(/[<>:"/\\|?*]/g,'_').trim();
const date     = (inv['Data'] || 'UNKNOWN').replace(/[<>:"/\\|?*]/g,'_');
const invNum   = (inv["'Numri i fatur\u00ebs"] || inv['Numri i fatur\u00ebs'] || 'UNKNOWN').replace(/[<>:"/\\|?*']/g,'_');
return { json: { excelBase64, archiveBase64, originalPath: data.originalPath, fileName: data.fileName, archiveSupplier: supplier, archiveDate: date, archiveInvNum: invNum } };

const { execSync } = require('child_process');
const excelBase64 = $json.excelBase64;
try {
  const result = execSync(
    'echo ' + excelBase64 + ' | base64 -d | python3 /scripts/excel_writer_lb.py /data/invoices/LB.xlsx',
    { encoding: 'utf8', shell: '/bin/sh', timeout: 60000 }
  );
  return { json: { stdout: result, status: 'excel_written' } };
} catch(e) {
  return { json: { stdout: '', stderr: String(e.message), status: 'excel_error' } };
}

const { execSync } = require('child_process');
const prepData      = $('Prepare JSON Base64').item.json;
const archiveBase64 = prepData.archiveBase64;
const originalPath  = prepData.originalPath;
try {
  const result = execSync(
    'mkdir -p /data/invoices/Completed && echo ' + archiveBase64 + ' | base64 -d | python3 /scripts/archive_lb_invoice.py "' + originalPath + '" /data/invoices/Completed',
    { encoding: 'utf8', shell: '/bin/sh', timeout: 30000 }
  );
  return { json: { stdout: result, status: 'archived' } };
} catch(e) {
  return { json: { stdout: '', stderr: String(e.message), status: 'archive_error' } };
}
